// G1 — Validação de entrada do Conferente
// Valida HMAC X-Normalizer-Signature, normalized_text e extraction_metadata

const crypto = require('crypto');

const body = $input.first().json.body;
const headers = $input.first().json.headers;

// --- Validação HMAC ---
const normalizerSecret = $env.NORMALIZER_SECRET;
if (!normalizerSecret) {
  throw new Error('G1_CONFIG_ERROR: NORMALIZER_SECRET não configurado');
}

const signatureHeader = headers['x-normalizer-signature'] || headers['X-Normalizer-Signature'] || '';
if (!signatureHeader) {
  throw new Error('G1_AUTH_FAILED: Header X-Normalizer-Signature ausente');
}

// Formato esperado: sha256=<hex>
const receivedHex = signatureHeader.replace('sha256=', '');
const rawBody = JSON.stringify(body);
const expectedHex = crypto
  .createHmac('sha256', normalizerSecret)
  .update(rawBody)
  .digest('hex');

const signatureValid = crypto.timingSafeEqual(
  Buffer.from(receivedHex, 'hex'),
  Buffer.from(expectedHex, 'hex')
);

if (!signatureValid) {
  throw new Error('G1_AUTH_FAILED: Assinatura HMAC inválida');
}

// --- Validação do payload ---
const { ingestion_id, project_id, normalized_text, extraction_metadata, provider_chain, callback_url } = body;

if (!ingestion_id || !/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(ingestion_id)) {
  throw new Error('G1_INVALID: ingestion_id deve ser UUID v4');
}

if (!project_id) {
  throw new Error('G1_INVALID: project_id ausente');
}

if (!normalized_text || typeof normalized_text !== 'string' || normalized_text.trim().length === 0) {
  throw new Error('G1_INVALID: normalized_text vazio ou ausente');
}

const MAX_CHARS = parseInt($env.MAX_NORMALIZED_CHARS || '200000', 10);
if (normalized_text.length > MAX_CHARS) {
  throw new Error(`G1_INVALID: normalized_text excede limite de ${MAX_CHARS} chars (recebido: ${normalized_text.length})`);
}

// Verificar encoding UTF-8 válido (Node.js trata strings como UTF-16; validar via Buffer)
try {
  Buffer.from(normalized_text, 'utf8').toString('utf8');
} catch (e) {
  throw new Error('G1_INVALID: normalized_text não é UTF-8 válido');
}

// extraction_metadata obrigatório
if (!extraction_metadata || typeof extraction_metadata !== 'object') {
  throw new Error('G1_INVALID: extraction_metadata ausente');
}

const requiredMetaFields = ['source_format', 'original_size_bytes', 'normalized_char_count', 'extraction_method'];
for (const field of requiredMetaFields) {
  if (extraction_metadata[field] === undefined || extraction_metadata[field] === null) {
    throw new Error(`G1_INVALID: extraction_metadata.${field} ausente`);
  }
}

if (!provider_chain || !Array.isArray(provider_chain) || provider_chain.length === 0) {
  throw new Error('G1_INVALID: provider_chain ausente ou vazia');
}

if (!callback_url) {
  throw new Error('G1_INVALID: callback_url ausente');
}

return [{
  json: {
    ingestion_id,
    project_id,
    normalized_text,
    extraction_metadata,
    provider_chain,
    callback_url,
    g1_validated_at: new Date().toISOString()
  }
}];

// Extrai JSON da resposta LLM (suporta Anthropic e DeepSeek/OpenAI-compat)

const llmResponse = $input.first().json;
const upstream = $('Montar prompt Conferente').first().json;

let rawText = '';

// Anthropic: choices inexistente, usa content[]
if (llmResponse.content && Array.isArray(llmResponse.content)) {
  rawText = llmResponse.content.map(c => c.text || '').join('');
} else if (llmResponse.choices && Array.isArray(llmResponse.choices)) {
  // OpenAI-compat (DeepSeek)
  rawText = llmResponse.choices[0]?.message?.content || '';
} else {
  throw new Error('PARSE_FAILED: Estrutura de resposta LLM desconhecida');
}

// Remove possíveis blocos markdown ```json ... ```
rawText = rawText.trim();
if (rawText.startsWith('```')) {
  rawText = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(rawText);
} catch (e) {
  throw new Error(`PARSE_FAILED: JSON inválido na resposta do Conferente: ${e.message}. Trecho: ${rawText.substring(0, 200)}`);
}

// Tokens consumidos
let tokensConsumed = { input: 0, output: 0 };
if (llmResponse.usage) {
  tokensConsumed = {
    input: llmResponse.usage.input_tokens || llmResponse.usage.prompt_tokens || 0,
    output: llmResponse.usage.output_tokens || llmResponse.usage.completion_tokens || 0
  };
}

return [{
  json: {
    ingestion_id: upstream.ingestion_id,
    project_id: upstream.project_id,
    normalized_text: upstream.normalized_text,
    extraction_metadata: upstream.extraction_metadata,
    provider_chain: upstream.provider_chain,
    callback_url: upstream.callback_url,
    doc_classification: parsed.doc_classification,
    active_personas: parsed.active_personas,
    shared_context: parsed.shared_context,
    chunking_strategy: parsed.chunking_strategy || 'single',
    tokens_consumed: tokensConsumed,
    parsed_at: new Date().toISOString()
  }
}];

// G2 — Valida que o roteamento produzido pelo LLM é coerente

const item = $input.first().json;

const TAGS_CANONICAS = new Set(['AUD', 'GP', 'ARQ', 'DBA', 'DEV', 'QA', 'UX', 'UI', 'SEG', 'CONF', 'LGPD', 'NEG']);
const CHUNK_STRATEGIES_VALIDAS = new Set(['single', 'section_split', 'hierarchical']);

const { active_personas, doc_classification, shared_context, chunking_strategy } = item;

if (!Array.isArray(active_personas) || active_personas.length === 0) {
  throw new Error('G2_INVALID: active_personas ausente ou vazio');
}

// Verifica que todas as tags são canônicas
const tagsInvalidas = active_personas.filter(t => !TAGS_CANONICAS.has(t));
if (tagsInvalidas.length > 0) {
  throw new Error(`G2_INVALID: Tags não-canônicas em active_personas: ${tagsInvalidas.join(', ')}`);
}

if (active_personas.length < 3) {
  throw new Error(`G2_INVALID: active_personas deve ter no mínimo 3 (recebido: ${active_personas.length})`);
}

// CONF e AUD são obrigatórios
if (!active_personas.includes('CONF')) {
  throw new Error('G2_INVALID: CONF (pilar bloqueante) deve estar sempre em active_personas');
}
if (!active_personas.includes('AUD')) {
  throw new Error('G2_INVALID: AUD (qualidade documental) deve estar sempre em active_personas');
}

if (!CHUNK_STRATEGIES_VALIDAS.has(chunking_strategy)) {
  throw new Error(`G2_INVALID: chunking_strategy inválido: ${chunking_strategy}`);
}

if (!doc_classification || !doc_classification.primary_type || !doc_classification.sensitivity) {
  throw new Error('G2_INVALID: doc_classification incompleto (primary_type ou sensitivity ausente)');
}

if (!shared_context || !shared_context.summary) {
  throw new Error('G2_INVALID: shared_context.summary ausente');
}

// GP é sempre ativado como orquestrador (não entra em active_personas mas é despachado)
// Remover GP de active_personas caso LLM o tenha incluído (ele tem workflow próprio)
const activePersonasFiltered = active_personas.filter(t => t !== 'GP');

return [{
  json: {
    ...item,
    active_personas: activePersonasFiltered,
    g2_validated_at: new Date().toISOString()
  }
}];

// Persiste metadados da ingestão no Redis via API HTTP do GCA Backend
// O GCA Backend expõe /api/internal/redis/set para o n8n (rede interna)

const item = $input.first().json;
const { ingestion_id, project_id, active_personas, shared_context, callback_url } = item;

// Monta o conjunto de chaves a persistir
const redisKeys = [
  {
    key: `gca:ingestion:${ingestion_id}:expected_count`,
    value: String(active_personas.length),
    ttl: 3600
  },
  {
    key: `gca:ingestion:${ingestion_id}:shared_context`,
    value: JSON.stringify(shared_context),
    ttl: 3600
  },
  {
    key: `gca:ingestion:${ingestion_id}:project_id`,
    value: project_id,
    ttl: 3600
  },
  {
    key: `gca:ingestion:${ingestion_id}:active_personas`,
    value: JSON.stringify(active_personas),
    ttl: 3600
  },
  {
    key: `gca:ingestion:${ingestion_id}:callback_url`,
    value: callback_url,
    ttl: 3600
  }
];

// Passa as chaves adiante para o nó HTTP que fará o SET no Redis
// O nó HTTP Request seguinte lida com a persistência real
return [{
  json: {
    ...item,
    redis_keys_to_set: redisKeys,
    redis_base_url: `${$env.GCA_CALLBACK_BASE_URL}/api/internal/redis`,
    expected_count: active_personas.length
  }
}];

// Emite 1 item por persona — HTTP Request seguinte itera sobre todos
const crypto = require('crypto');
const upstream = $('G2 - Validar roteamento').first().json;
const { ingestion_id, project_id, normalized_text, extraction_metadata, provider_chain, callback_url, active_personas, shared_context, doc_classification, chunking_strategy } = upstream;
const conferenteSecret = $env.CONFERENTE_SECRET;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://n8n-pipeline.mockn8n.com';

const items = [];
for (const tag of active_personas) {
  const tagLower = tag.toLowerCase();
  const webhookUrl = `${n8nBaseUrl}/webhook/gca-specialist-${tagLower}`;
  const payload = {
    ingestion_id, project_id, normalized_text, extraction_metadata,
    provider_chain, callback_url, shared_context, doc_classification,
    chunking_strategy, persona_tag: tag, dispatched_at: new Date().toISOString()
  };
  const payloadStr = JSON.stringify(payload);
  const hmac = 'sha256=' + crypto.createHmac('sha256', conferenteSecret).update(payloadStr).digest('hex');
  items.push({json: {webhook_url: webhookUrl, hmac_signature: hmac, payload: payloadStr}});
}
return items;

// Despacha o GP Orquestrador com o resultado da classificação
// GP sempre é ativado, independente de estar em active_personas

const crypto = require('crypto');

const upstream = $('G2 - Validar roteamento').first().json;
const conferenteSecret = $env.CONFERENTE_SECRET;
const n8nBaseUrl = $env.N8N_BASE_URL || 'https://n8n-pipeline.mockn8n.com';

const payload = {
  ingestion_id: upstream.ingestion_id,
  project_id: upstream.project_id,
  normalized_text: upstream.normalized_text,
  extraction_metadata: upstream.extraction_metadata,
  provider_chain: upstream.provider_chain,
  callback_url: upstream.callback_url,
  doc_classification: upstream.doc_classification,
  active_personas: upstream.active_personas,
  shared_context: upstream.shared_context,
  chunking_strategy: upstream.chunking_strategy,
  dispatched_at: new Date().toISOString()
};

const payloadStr = JSON.stringify(payload);
const hmac = crypto
  .createHmac('sha256', conferenteSecret)
  .update(payloadStr)
  .digest('hex');

return [{
  json: {
    gp_webhook_url: `${n8nBaseUrl}/webhook/gca-orchestrator-gp`,
    gp_hmac: `sha256=${hmac}`,
    gp_payload: payload
  }
}];

// Handler global de erro — captura falhas dos nós anteriores
// Preserva ingestion_id e project_id se disponíveis na cadeia

const errorData = $input.first();
const errorMessage = errorData.json.error?.message || errorData.json.message || 'Erro desconhecido no workflow Conferente';

// Tenta recuperar contexto de qualquer nó anterior que teve sucesso
let ingestion_id = 'unknown';
let project_id = 'unknown';

try {
  const webhookData = $('Webhook Trigger').first().json;
  ingestion_id = webhookData.body?.ingestion_id || 'unknown';
  project_id = webhookData.body?.project_id || 'unknown';
} catch (_) {
  // Sem contexto disponível
}

return [{
  json: {
    ingestion_id,
    project_id,
    error: { message: errorMessage },
    failed_at: new Date().toISOString()
  }
}];
